class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        platform: ESPlatform,
        service: str = "central-platform",
        environment: str = "dev",
        logger_name: Optional[str] = None,
        level: int = logging.INFO,
        flush_interval: float = 0.0,
    ):
        super().__init__(level=level)
        self.platform = platform
        self.service = service
        self.environment = environment
        self.logger_name = logger_name
        self.flush_interval = float(flush_interval)
        self._last_emit = 0.0

    def emit(self, record: logging.LogRecord) -> None:
        try:
            msg = self.format(record) if self.formatter else record.getMessage()
            err = None
            if record.exc_info:
                err = {
                    "type": ensure_str(getattr(record.exc_info[0], "__name__", "Exception")),
                    "message": ensure_str(record.exc_info[1]),
                }
            fields = {
                "module": record.module,
                "funcName": record.funcName,
                "pathname": record.pathname,
                "lineno": record.lineno,
                "process": record.process,
                "thread": record.thread,
            }
            for k in ("trace_id", "span_id", "request_id", "user_id", "event_type"):
                if hasattr(record, k):
                    fields[k] = getattr(record, k)

            self.platform.index_log(
                message=msg,
                level=record.levelname,
                logger=self.logger_name or record.name,
                service=self.service,
                environment=self.environment,
                trace_id=getattr(record, "trace_id", None),
                span_id=getattr(record, "span_id", None),
                request_id=getattr(record, "request_id", None),
                user_id=getattr(record, "user_id", None),
                event_type=getattr(record, "event_type", None),
                error=err,
                fields=fields,
            )

            if self.flush_interval > 0:
                now = time.time()
                if now - self._last_emit >= self.flush_interval:
                    self._last_emit = now
        except Exception:
            self.handleError(record)


def build_arg_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(description="Centralized Elasticsearch logging and search platform (elasticsearch-py).")
    p.add_argument("--host", default=os.getenv("ES_HOST", "http://localhost:9200"), help="Elasticsearch URL")
    p.add_argument("--docs-index", default=os.getenv("ES_DOCS_INDEX", "documents"))
    p.add_argument("--logs-prefix", default=os.getenv("ES_LOGS_PREFIX", "logs"))
    p.add_argument("--env", default=os.getenv("APP_ENV", "dev"))
    p.add_argument("--service", default=os.getenv("APP_SERVICE", "central-platform"))

    sub = p.add_subparsers(dest="cmd", required=True)

    idx = sub.add_parser("index-doc", help="Index a document for full-text search")
    idx.add_argument("--title", required=True)
    idx.add_argument("--content", required=True)
    idx.add_argument("--tags", default="")
    idx.add_argument("--source", default="app")
    idx.add_argument("--id", default=None)

    s = sub.add_parser("search-docs", help="Search documents")
    s.add_argument("--q", required=True)
    s.add_argument("--tags", default="")
    s.add_argument("--source", default=None)
    s.add_argument("--from", dest="from_", type=int, default=0)
    s.add_argument("--size", type=int, default=10)

    l = sub.add_parser("log", help="Index a log event")
    l.add_argument("--message", required=True)
    l.add_argument("--level", default="INFO")
    l.add_argument("--logger", default="app")
    l.add_argument("--event-type", default=None)
    l.add_argument("--trace-id", default=None)
    l.add_argument("--request-id", default=None)
    l.add_argument("--user-id", default=None)
    l.add_argument("--fields", default=None, help="JSON dict of additional fields")

    ls = sub.add_parser("search-logs", help="Search logs")
    ls.add_argument("--q", default=None)
    ls.add_argument("--level", default=None)
    ls.add_argument("--service", default=None)
    ls.add_argument("--event-type", default=None)
    ls.add_argument("--start", default=None, help="ISO8601 or date math")
    ls.add_argument("--end", default=None, help="ISO8601 or date math")
    ls.add_argument("--from", dest="from_", type=int, default=0)
    ls.add_argument("--size", type=int, default=50)
    ls.add_argument("--indices", default=None)

    a = sub.add_parser("aggregate-logs", help="Aggregate logs by group and time interval")
    a.add_argument("--group-by", default="level", help="Field to group by (e.g., level, service, event_type, host)")
    a.add_argument("--interval", default="1h", help="fixed_interval for date_histogram, e.g., 5m, 1h, 1d")
    a.add_argument("--q", default=None)
    a.add_argument("--level", default=None)
    a.add_argument("--service", default=None)
    a.add_argument("--start", default=None)
    a.add_argument("--end", default=None)
    a.add_argument("--indices", default=None)
    a.add_argument("--size-terms", type=int, default=20)

    return p


def parse_csv(v: Optional[str]) -> List[str]:
    if not v:
        return []
    return [x.strip() for x in v.split(",") if x.strip()]


def main() -> int:
    args = build_arg_parser().parse_args()
    platform = ESPlatform(
        hosts=[args.host],
        docs_index=args.docs_index,
        logs_index_prefix=args.logs_prefix,
    )

    if not platform.ping():
        raise SystemExit(f"Elasticsearch not reachable at {args.host}")

    if args.cmd == "index-doc":
        tags = parse_csv(args.tags)
        doc_id = platform.index_document(
            title=args.title,
            content=args.content,
            tags=tags,
            source=args.source,
            doc_id=args.id,
            refresh="wait_for",
        )
        print(json.dumps({"indexed": True, "doc_id": doc_id}, ensure_ascii=False))
        return 0

    if args.cmd == "search-docs":
        tags = parse_csv(args.tags)
        res = platform.search_documents(
            query=args.q,
            tags=tags or None,
            source=args.source,
            from_=args.from_,
            size=args.size,
        )
        print(json.dumps(res, ensure_ascii=False))
        return 0

    if args.cmd == "log":
        fields = None
        if args.fields:
            fields = json.loads(args.fields)
            if not isinstance(fields, dict):
                raise SystemExit("--fields must be a JSON object/dict")
        log_id = platform.index_log(
            message=args.message,
            level=args.level,
            logger=args.logger,
            service=args.service,
            environment=args.env,
            trace_id=args.trace_id,
            request_id=args.request_id,
            user_id=args.user_id,
            event_type=args.event_type,
            fields=fields,
            refresh="wait_for",
        )
        print(json.dumps({"logged": True, "log_id": log_id, "index": platform.logs_index_name()}, ensure_ascii=False))
        return 0

    if args.cmd == "search-logs":
        level = None
        if args.level:
            if "," in args.level:
                level = parse_csv(args.level)
            else:
                level = args.level
        res = platform.search_logs(
            query=args.q,
            level=level,
            service=args.service or args.service,
            environment=args.env,
            event_type=args.event_type,
            start=args.start,
            end=args.end,
            from_=args.from_,
            size=args.size,
            indices=args.indices,
        )
        print(json.dumps(res, ensure_ascii=False))
        return 0

    if args.cmd == "aggregate-logs":
        level = None
        if args.level:
            if "," in args.level:
                level = parse_csv(args.level)
            else:
                level = args.level
        res = platform.aggregate_logs(
            group_by=args.group_by,
            interval=args.interval,
            query=args.q,
            service=args.service or args.service,
            environment=args.env,
            level=level,
            start=args.start,
            end=args.end,
            indices=args.indices,
            size_terms=args.size_terms,
        )
        print(json.dumps(res, ensure_ascii=False))
        return 0

    return 2


if __name__ == "__main__":
    main()